export const getSaveRecipeUrl = () => {




  return `/api/saved/recipes`
}

/**
 * @summary Save a recipe
 */
export const saveRecipe = async (saveItemInput: SaveItemInput, options?: RequestInit): Promise<void> => {

  return customFetch<void>(getSaveRecipeUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      saveItemInput,)
  }
);}




